INSERT INTO `achievement_locale` (`ID`, `locale`, `Description_lang`, `Title_lang`, `Reward_lang`, `VerifiedBuild`) VALUES
(62773, 'esES', 'Completa los siguientes logros de Pescadores del abismo.', 'Pescadores del abismo: rival de Je\'ju', '', 67186),
(61883, 'esES', 'Evita que te pillen durante el primer minuto en Duelo de adornos (x3).', 'Ahora no me ves...', '', 67186),
(61887, 'esES', 'Completa todos los logros de Duelo de adornos.', 'Disfraz de primera', '', 67186),
(61886, 'esES', 'Consigue acceder a todas las mejoras de kits en Duelo de adornos.', 'Equipación completa', '', 67186),
(61882, 'esES', 'Después de que te encuentren, consigue que te pierdan la pista antes de que te pillen en Duelo de adornos.', 'Por los pelos', '', 67186),
(61881, 'esES', 'Sé el último escondido sin pillar de tu equipo en Duelo de adornos.', 'Escondite infalible', '', 67186),
(61880, 'esES', 'Escóndete y evita que te encuentren durante un minuto y medio seguido en Duelo de adornos.', 'Qué frío hace a la sombra', '', 67186),
(61879, 'esES', 'Gana una ronda como buscador tras pillar a todos los escondidos en dos minutos o menos en Duelo de adornos.', 'Tú la llevas', '', 67186),
(61878, 'esES', 'Como forestal Arcano, consigue pillar a jugadores enemigos en Duelo de adornos.', 'Pillado y hundido', '', 67186),
(61793, 'esES', 'Como nulificador, consigue pillar a jugadores enemigos en Duelo de adornos.', 'Herramienta del Vacío', '', 67186),
(61792, 'esES', 'Como rompehechizos, consigue pillar a jugadores enemigos en Duelo de adornos.', '¡Te pillé!', '', 67186),
(63263, 'esES', '', '[DNT]Midnight Keystone Myth: Season One Personal Achievement', '', 67186),
(63097, 'esES', 'Consigue un índice de mítica+ de al menos 3400 durante la temporada 1 de Midnight.', 'Mito de la piedra angular de Midnight: temporada 1', 'Título: el Contendiente Umbrío y Objeto: silla de montar perdida en el tiempo', 67186),
(61594, 'esES', 'Consigue la mejor puntuación de tu región en la mazmorra de piedra angular del Trecho Celestial.', 'Vencedor de piedra angular: Trecho Celestial', '', 67186),
(61593, 'esES', 'Consigue la mejor puntuación de tu región en la mazmorra de piedra angular del Trono del Triunvirato.', 'Vencedor de piedra angular: Trono del Triunvirato', '', 67186),
(61592, 'esES', 'Consigue la mejor puntuación de tu región en la mazmorra de piedra angular del Foso de Saron.', 'Vencedor de piedra angular: Foso de Saron', '', 67186),
(61591, 'esES', 'Consigue la mejor puntuación de tu región en la mazmorra de piedra angular de la Academia Algeth\'ar.', 'Vencedor de piedra angular: Academia Algeth\'ar', '', 67186),
(61590, 'esES', 'Consigue la mejor puntuación de tu región en la mazmorra de piedra angular de la Aguja Brisaveloz.', 'Vencedor de piedra angular: Aguja Brisaveloz', '', 67186),
(61589, 'esES', 'Consigue la mejor puntuación de tu región en la mazmorra de piedra angular del Punto de Nexo: Xenas.', 'Vencedor de piedra angular: Punto de Nexo: Xenas', '', 67186),
(61588, 'esES', 'Consigue la mejor puntuación de tu región en la mazmorra de piedra angular de las Cavernas de Maisara.', 'Vencedor de piedra angular: Cavernas de Maisara', '', 67186),
(61587, 'esES', 'Consigue la mejor puntuación de tu región en la mazmorra de piedra angular del Bancal del Magister (Midnight).', 'Vencedor de piedra angular: Bancal del Magister (Midnight)', '', 67186),
(61259, 'esES', 'Termina la temporada 1 de míticas+ de Midnight con un índice de mítica+ entre el 0,1% de los mejores jugadores de tu región.', 'Héroe Umbrío: temporada 1 de Midnight', 'Título: el Héroe Umbrío', 67186),
(61253, 'esES', 'Completa todas las mazmorras míticas+ de nivel de piedra angular 30 dentro del límite de tiempo durante la temporada 1 de Midnight.', 'Temporada 1 de Midnight: piedra angular resiliente 30', 'Las piedras angulares ya no se reducirán por debajo del nivel 30 durante la temporada 1 de Midnight.', 67186),
(61252, 'esES', 'Completa todas las mazmorras míticas+ de nivel de piedra angular 29 dentro del límite de tiempo durante la temporada 1 de Midnight.', 'Temporada 1 de Midnight: piedra angular resiliente 29', 'Las piedras angulares ya no se reducirán por debajo del nivel 29 durante la temporada 1 de Midnight.', 67186),
