INSERT INTO `currency_types_locale` (`ID`, `locale`, `Name_lang`, `Description_lang`, `VerifiedBuild`) VALUES
(3513, 'esES', 'Núcleo de Vacío nebuloso', 'Se puede transmutar en equipo de gran poder tras derrotar a enemigos peligrosos en bandas de la temporada 1 de Midnight o completar mazmorras míticas+, profundidades pródigas y cacerías de Presa en dificultad pesadilla.', 67186),
(3347, 'esES', 'Blasón del alba de mito', 'Se usa para mejorar el equipo de mito durante la temporada 1 de Midnight hasta los niveles de objeto 276-289.\n\nCuando se usa para artesanía, establece el nivel de objeto del objeto resultante en 272-285 en función de la calidad.\n\nSe obtiene en las siguientes actividades:\n\n- Aguja del Vacío, la Falla Onírica y Marcha a Quel\'Danas en dificultad mítica\n- Mazmorras de piedra angular mítica (+9 y superiores)', 67186),
(3346, 'esES', 'Blasón del alba de héroe', 'Se usa para mejorar el equipo de héroe durante la temporada 1 de Midnight hasta los niveles de objeto 263-276. Se obtiene en las siguientes actividades:\n\n- Aguja del Vacío, la Falla Onírica y Marcha a Quel\'Danas en dificultad heroica\n- Mazmorras de piedra angular mítica (de +4 a +8)\n- Profundidades (nivel 11)\n- Botín de cazatesoros (nivel 8+)\n- Cacerías de Presas (pesadilla)', 67186),
(3345, 'esES', 'Blasón del alba de héroe', 'Se usa para mejorar el equipo de héroe durante la temporada 1 de Midnight hasta los niveles de objeto 263-276.\n\nCuando se usa para artesanía, establece el nivel de objeto del objeto resultante en 259-272 en función de la calidad.\n\nSe obtiene en las siguientes actividades:\n\n- Aguja del Vacío, la Falla Onírica y Marcha a Quel\'Danas en dificultad heroica\n- Mazmorras de piedra angular mítica (de +4 a +8)\n- Profundidades (nivel 11)\n- Botín de cazatesoros (nivel 8+)\n- Cacerías de Presas (pesadilla)', 67186),
(3344, 'esES', 'Blasón del alba de campeón', 'Se usa para mejorar el equipo de campeón durante la temporada 1 de Midnight hasta los niveles de objeto 250-263. Se obtiene en las siguientes actividades:\n\n- Eventos del mundo semanales\n- Aguja del Vacío, la Falla Onírica y Marcha a Quel\'Danas en dificultad normal\n- Mazmorras de temporada en dificultad mítica\n- Mazmorras de piedra angular mítica (+2 y +3)\n- Profundidades (niveles 7-10)\n- Botín de cazatesoros (niveles 6-7)\n- Cacerías de Presas (pesadilla)', 67186),
(3343, 'esES', 'Blasón del alba de campeón', 'Se usa para mejorar el equipo de campeón durante la temporada 1 de Midnight hasta los niveles de objeto 250-263. Se obtiene en las siguientes actividades:\n\n- Eventos del mundo semanales\n- Aguja del Vacío, la Falla Onírica y Marcha a Quel\'Danas en dificultad normal\n- Mazmorras de temporada en dificultad mítica\n- Mazmorras de piedra angular mítica (+2 y +3)\n- Profundidades (niveles 7-10)\n- Botín de cazatesoros (niveles 6-7)\n- Cacerías de Presas (pesadilla)', 67186),
(3342, 'esES', 'Blasón del alba de veterano', 'Se usa para mejorar el equipo de veterano durante la temporada 1 de Midnight hasta los niveles de objeto 237-250. Se obtiene en las siguientes actividades:\n\n- Eventos del mundo repetibles\n- Aguja del Vacío, la Falla Onírica y Marcha a Quel\'Danas en dificultad buscador de bandas\n- Mazmorras de temporada en dificultad heroica\n- Profundidades (niveles 5-6)\n- Botín de cazatesoros (niveles 4-5)\n- Cacerías de Presas (difícil)', 67186),
(3341, 'esES', 'Blasón del alba de veterano', 'Se usa para mejorar el equipo de veterano durante la temporada 1 de Midnight hasta los niveles de objeto 237-250.\n\nCuando se usa para artesanía, establece el nivel de objeto del objeto resultante en 233-246 en función de la calidad.\n\nSe obtiene en las siguientes actividades:\n\n- Eventos del mundo repetibles\n- Aguja del Vacío, la Falla Onírica y Marcha a Quel\'Danas en dificultad buscador de bandas\n- Mazmorras de temporada en dificultad heroica\n- Profundidades (niveles 5-6)\n- Botín de cazatesoros (niveles 4-5)\n- Cacerías de Presas (difícil)', 67186),
(3418, 'esES', 'Núcleo de Vacío nebuloso', 'Se puede transmutar en equipo de gran poder tras derrotar a enemigos peligrosos en bandas de la temporada 1 de Midnight o completar mazmorras míticas+, profundidades pródigas y cacerías de Presa en dificultad pesadilla.', 67186),
(3391, 'esES', 'Blasón del alba de aventurero', 'Se usa para mejorar el equipo de aventurero durante la temporada 1 de Midnight hasta los niveles de objeto 224-237. Se obtiene en las siguientes actividades:\n\n- Eventos del mundo repetibles\n- Profundidades de nivel 4\n- Cacerías de Presas (normal)', 67186),
(3383, 'esES', 'Blasón del alba de aventurero', 'Se usa para mejorar el equipo de aventurero durante la temporada 1 de Midnight hasta los niveles de objeto 224-237.\n\nCuando se usa para artesanía, establece el nivel de objeto del objeto resultante en 220-233 en función de la calidad.\n\nSe obtiene en las siguientes actividades:\n\n- Eventos del mundo repetibles\n- Profundidades de nivel 4\n- Cacerías de Presas (normal)', 67186),
(3348, 'esES', 'Blasón del alba de mito', 'Se usa para mejorar el equipo de mito durante la temporada 1 de Midnight hasta los niveles de objeto 276-289. Se obtiene en las siguientes actividades:\n\n- Aguja del Vacío, la Falla Onírica y Marcha a Quel\'Danas en dificultad heroica\n- Mazmorras de piedra angular mítica (+9 y superiores)', 67186);
