INSERT INTO `journal_encounter_section_locale` (`ID`, `locale`, `Title_lang`, `BodyText_lang`, `VerifiedBuild`) VALUES
(32672, 'esES', 'Tanques', '$bullet;El Acaparatesoros reúne recursos de la pila más cercana durante |cFF2959D3|Hspell:1235072|h[Medidas ingeniosas]|h|r.\n$bullet;Los champiñones podridos aplican |cFF2959D3|Hspell:1234846|h[Esporas tóxicas]|h|r al contacto, lo que evita que se ejecute |cFF2959D3|Hspell:1245593|h[Ráfaga pútrida]|h|r.\n$bullet;|cFF2959D3|Hspell:1234681|h[Bramido voraz]|h|r y |cFF2959D3|Hspell:1235125|h[Bramido potente]|h|r infligen mucho daño a todos los jugadores.', 67186),
(32669, 'esES', 'Resumen', 'El Acaparatesoros evita que saqueen sus reservas a toda costa y, al llegar al 90%, 60% y 30% de la salud, lanzará |cFF2959D3|Hspell:1235072|h[Medidas ingeniosas]|h|r lo que potenciará una de sus facultades.\n\nAl llegar a 100 p. de energía, lanza |cFF2959D3|Hspell:1234233|h[Suministros caducados]|h|r por la arena, que generan champiñones podridos durante 12 s. Dichos champiñones aplican |cFF2959D3|Hspell:1234846|h[Esporas tóxicas]|h|r y, al entrar en contacto con ellos, destruyen el hongo, lo que previene una |cFF2959D3|Hspell:1245593|h[Ráfaga pútrida]|h|r.', 67186),
(31527, 'esES', 'Flete Prohibido', 'Un envío pensado para mantenerse a salvo de las miradas indiscretas. Proporciona una excelente fuente de cobertura.', 67186),
(31282, 'esES', 'Tanque', '$bullet;Kystia hace que Dentellón muestre hostilidad hacia los jugadores con |cFF2959D3|Hspell:1230289|h[Infusión ilícita]|h|r.\n$bullet;Evita el |cFF2959D3|Hspell:1253811|h[Pulverizador vil]|h|r de Dentellón.\n$bullet;Interrumpe los |cFF2959D3|Hspell:1264095|h[Reflejos exactos]|h|r de Kystia.', 67186),
(31281, 'esES', 'Sanadores', '$bullet;Kystia hace que Dentellón muestre hostilidad hacia los jugadores con |cFF2959D3|Hspell:1230289|h[Infusión ilícita]|h|r.\n$bullet;Evita el |cFF2959D3|Hspell:1253811|h[Pulverizador vil]|h|r de Dentellón.\n$bullet;Kystia inflige mucho daño a todos los jugadores con |cFF2959D3|Hspell:1265412|h[Desestabilizado]|h|r.', 67186),
(31280, 'esES', 'DPS', '$bullet;Kystia hace que Dentellón muestre hostilidad hacia los jugadores con |cFF2959D3|Hspell:1230289|h[Infusión ilícita]|h|r.\n$bullet;Evita el |cFF2959D3|Hspell:1253811|h[Pulverizador vil]|h|r de Dentellón.\n$bullet;Interrumpe los |cFF2959D3|Hspell:1264095|h[Reflejos exactos]|h|r de Kystia.', 67186),
(35862, 'esES', 'Section 18', '', 67186),
(35353, 'esES', 'Sección 17', '|n\nBy speaking with Lindormi near The Timeways portal or at the end of a Keystone Dungeon, characters with a tank specialization can enable |cFF2959D3|Hspell:1295986|h[Lindormi\'s Glow]|h|r when |cFF2959D3|Hspell:1278156|h[Lindormi\'s Guidance]|h|r is inactive.', 67186),
(34751, 'esES', 'Sección 17', '', 67186),
(34733, 'esES', 'Argucia de Xal\'atath', 'Xal\'atath traiciona a los jugadores, lo que anula sus tratos y provoca que, al morir, se reduzca en 15 s tiempo restante.', 67186),
(34732, 'esES', 'Reforzada', 'Los enemigos que no son jefes tienen un 20% más de salud e infligen hasta un 20% más de daño.', 67186),
(34731, 'esES', 'Tiránica', 'Los jefes tienen un 25% más de salud. Los jefes y sus esbirros infligen hasta un 15% más de daño.', 67186),
(34730, 'esES', 'Tiránica y Reforzada', 'Estos afijos potencian más a los enemigos de las mazmorras de piedra angular mítica. Uno se activa en el nivel 7 mítico, el otro, en el nivel 10 mítico; cambian cada semana.', 67186),
(34727, 'esES', 'Trato de Xal\'atath: Devorar', '', 67186),
(34725, 'esES', 'Trato de Xal\'atath: Ligada al Vacío', '', 67186),
(34722, 'esES', 'Trato de Xal\'atath: Púlsar', '', 67186),
(34720, 'esES', 'Nivel 6 mítico', '$bullet;Se ha eliminado |cFF2959D3|Hspell:1284818|h[Guía de Lindormi]|h|r.\n\nLos personajes con especialización de tanque pueden hablar con Lindormi junto al portal a las Líneas temporales o al final de una mazmorra de piedra angular para obtener |cFF2959D3|Hspell:1295986|h[Brillo de Lindormi]|h|r, que seguirá resaltando a las fuerzas enemigas.', 67186),
(35809, 'esES', 'Section 158', '', 67186),
(35491, 'esES', 'Sección 69', '', 67186),
(35490, 'esES', 'Sección 70', '', 67186),
(35489, 'esES', 'Sección 76', '', 67186),
(35488, 'esES', 'Sección 67', '$[!15,16\nEn dificultad heroica o superior, Galvanizar libera una Corriente de exterminio.$]', 67186),
(35477, 'esES', 'Sección 22', '', 67186),
