INSERT INTO `mail_template_locale` (`ID`, `locale`, `Body_lang`, `VerifiedBuild`) VALUES
(659, 'esES', '¡Saludos!\n\n¡Contempla las maravillas de este dominio rebosante de ABUNDANCIA GLORIOSA! ¡Se expande, se hincha, rechaza toda contención!\n\nTu devoción a mi divino yo merece un detallito. ¡Esta vez, en forma de abundancia sin alear!\n\nY toma nota: a partir de ahora aparecerán ciertas ofrendas, como la vitalidad fundida, en otros proveedores. Puede que los encuentres si tus pasos te llevan cerca de las Profundidades de Zul\'Aman.\n\nTe deseo las mejores cosechas,\n\n-Dundun, loa de la abundancia', 67186);
